{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization task involving spatial search, noise handling, and cost minimization. I am breaking it down into geometric modeling, probabilistic query optimization, and cost-function analysis.",
  "helpers": [
    {
      "label": "geometric_modeler",
      "instructions": "Represent the set of known polyomino shapes as a collection of relative coordinate sets. Create a function that, given a set of candidate placements on a grid, identifies the intersection of all possible valid configurations that satisfy a set of observed 'oil' or 'no oil' cell constraints."
    },
    {
      "label": "probabilistic_query_optimizer",
      "instructions": "Given a set of candidate polyomino placements and a noisy aggregate query model (where a query returns a signal with a known error distribution), calculate the information gain (expected reduction in entropy) for different drilling locations and aggregate query regions. Rank the most efficient probes to distinguish between competing placement hypotheses."
    },
    {
      "label": "cost_function_analyst",
      "instructions": "Define a mathematical objective function that balances the cost of individual drilling probes, the cost of aggregate queries, and the penalty for incorrect cells in the final guess. Analyze the trade-off between spending more on queries to reduce uncertainty versus the risk of high-cost errors in the final output."
    }
  ],
  "synthesis_brief": "Combine the geometric constraints from the geometric_modeler with the information gain rankings from the probabilistic_query_optimizer. Use the cost_function_analyst to determine the stopping criterion: when the expected cost of further probing exceeds the expected penalty of the current best guess, terminate the search and output the most probable cell configuration."
}

